use distributed_inference::text_topology::{
    analyze_image_file, build_bridge_entries, build_mesh_text_admission_ledger,
    build_residual_review_queue, build_residual_text_artifacts, build_rosetta_candidates,
    build_text_line_candidates, write_cleared_text_like_preview, write_depth_probe_images,
    write_pixel_moa_probe_image, write_surface_fragment_probe_image,
    write_surface_mask_probe_image, write_text_region_cutout, write_text_region_cutout_preview,
    write_text_region_mask, TextTopologyConfig, TextTopologyExample,
};
use serde::Serialize;
use std::collections::HashSet;
use std::env;
use std::fs::{self, File};
use std::io::{BufWriter, Write};
use std::path::{Path, PathBuf};

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct RosettaImportPayload {
    run: RosettaRun,
    metrics: Vec<RosettaMetric>,
    candidate_ranking: RosettaCandidateRanking,
    artifacts: RosettaArtifacts,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct RosettaRun {
    slug: String,
    label: String,
    source_type: String,
    source_uri: String,
    input: serde_json::Value,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct RosettaMetric {
    iteration: u32,
    best_fitness: f32,
    anchor_recovery: f32,
    anchors_matched: u32,
    anchors_total: u32,
    collision_count: u32,
    trend: String,
    raw: serde_json::Value,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct RosettaCandidateRanking {
    generated_at: String,
    iterations: u32,
    top_candidates: Vec<ImportCandidate>,
    last_summary: serde_json::Value,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct RosettaArtifacts {
    text_topology_corpus: serde_json::Value,
    text_topology_bridge: serde_json::Value,
    text_line_candidates: serde_json::Value,
    residual_text_artifacts: serde_json::Value,
    residual_review_queue: serde_json::Value,
    mesh_text_admission_ledger: serde_json::Value,
    image_summary: serde_json::Value,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct ImportCandidate {
    symbol: String,
    consensus_target: String,
    consensus_confidence: f32,
    utility_band: String,
    best_candidate: ImportBestCandidate,
    alternates: Vec<ImportAlternate>,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct ImportBestCandidate {
    predicted_meaning: String,
    score: f32,
    support: f32,
    support_count: u32,
    avg_confidence: f32,
    matched_ratio: f32,
    collision_size: u32,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct ImportAlternate {
    predicted_meaning: String,
    score: f32,
}

fn main() -> Result<(), String> {
    let args = Args::parse(env::args().skip(1).collect())?;
    fs::create_dir_all(&args.out_dir).map_err(|e| e.to_string())?;

    let mut paths = collect_images(&args.input)?;
    paths.sort();
    if let Some(limit) = args.limit {
        paths.truncate(limit);
    }

    let config = TextTopologyConfig {
        ink_threshold: args.threshold,
        ..TextTopologyConfig::default()
    };

    let mut examples = Vec::new();
    let mut example_sources = Vec::new();
    for path in paths {
        let mut example = analyze_image_file(&path, &config)?;
        if let Ok(relative) = path.strip_prefix(&args.input) {
            example.path = relative.to_string_lossy().to_string();
        }
        example_sources.push(path);
        examples.push(example);
    }

    let jsonl_path = args.out_dir.join("text-topology-corpus.jsonl");
    write_examples_jsonl(&jsonl_path, &examples)?;

    let payload = build_payload(&args, &examples)?;
    let payload_path = args.out_dir.join("rosetta-import-payload.json");
    let payload_json = serde_json::to_string_pretty(&payload).map_err(|e| e.to_string())?;
    fs::write(&payload_path, payload_json).map_err(|e| e.to_string())?;

    println!("examples={}", examples.len());
    println!("manifest={}", jsonl_path.display());
    println!("rosetta_payload={}", payload_path.display());

    if args.emit_cleared {
        let cleared_dir = args.out_dir.join("cleared");
        let mut cleared_images = 0_usize;
        for (example, source) in examples.iter().zip(example_sources.iter()) {
            let destination = cleared_dir.join(format!("{}.cleared.png", example.image_id));
            let cleared_pixels = write_cleared_text_like_preview(
                source,
                &destination,
                &config,
                args.clear_threshold,
                args.clear_radius,
                args.clear_iterations,
                args.clear_residual_threshold,
                args.clear_region_radius,
                args.clear_pixel_moa_recovery,
            )?;
            if cleared_pixels > 0 {
                cleared_images += 1;
            }
            if args.emit_region_masks {
                let mask_destination =
                    cleared_dir.join(format!("{}.text-region-mask.png", example.image_id));
                write_text_region_mask(
                    source,
                    &mask_destination,
                    &config,
                    args.clear_threshold,
                    args.clear_region_radius,
                )?;
            }
            if args.emit_text_cutouts {
                let cutout_destination =
                    cleared_dir.join(format!("{}.text-region-cutout.png", example.image_id));
                write_text_region_cutout(
                    source,
                    &cutout_destination,
                    &config,
                    args.clear_threshold,
                    args.clear_region_radius,
                )?;
                let preview_destination = cleared_dir.join(format!(
                    "{}.text-region-cutout-preview.png",
                    example.image_id
                ));
                write_text_region_cutout_preview(
                    source,
                    &preview_destination,
                    &config,
                    args.clear_threshold,
                    args.clear_region_radius,
                )?;
            }
            if args.emit_depth_probes {
                let depth_destination =
                    cleared_dir.join(format!("{}.depth-probe.png", example.image_id));
                let confidence_destination =
                    cleared_dir.join(format!("{}.depth-confidence.png", example.image_id));
                write_depth_probe_images(
                    source,
                    &depth_destination,
                    &confidence_destination,
                    args.monocular_cue_blend,
                )?;
            }
            if args.emit_pixel_moa_probes {
                let moa_destination =
                    cleared_dir.join(format!("{}.pixel-moa-probe.png", example.image_id));
                write_pixel_moa_probe_image(source, &moa_destination, &config)?;
            }
            if args.emit_surface_probes {
                let surface_destination =
                    cleared_dir.join(format!("{}.surface-mask-probe.png", example.image_id));
                write_surface_mask_probe_image(source, &surface_destination, &config)?;
                let fragment_destination =
                    cleared_dir.join(format!("{}.surface-fragment-probe.png", example.image_id));
                write_surface_fragment_probe_image(
                    source,
                    &fragment_destination,
                    &config,
                    args.clear_threshold,
                )?;
            }
        }
        println!("cleared_dir={}", cleared_dir.display());
        println!("cleared_images={}", cleared_images);
    }
    Ok(())
}

#[derive(Debug)]
struct Args {
    input: PathBuf,
    out_dir: PathBuf,
    threshold: u8,
    limit: Option<usize>,
    candidate_limit: usize,
    slug: String,
    source_uri: String,
    emit_cleared: bool,
    clear_threshold: f32,
    clear_radius: u32,
    clear_iterations: u32,
    clear_residual_threshold: f32,
    clear_region_radius: u32,
    clear_pixel_moa_recovery: bool,
    emit_region_masks: bool,
    emit_text_cutouts: bool,
    emit_depth_probes: bool,
    emit_pixel_moa_probes: bool,
    emit_surface_probes: bool,
    monocular_cue_blend: f32,
}

impl Args {
    fn parse(argv: Vec<String>) -> Result<Self, String> {
        let mut input: Option<PathBuf> = None;
        let mut out_dir = PathBuf::from("text-topology-corpus");
        let mut threshold = 125_u8;
        let mut limit: Option<usize> = None;
        let mut candidate_limit = 250_usize;
        let mut slug = "why-text-topology-v1".to_string();
        let mut source_uri = "__why-20260512T012424Z-3-001.zip".to_string();
        let mut emit_cleared = false;
        let mut clear_threshold = 0.75_f32;
        let mut clear_radius = 1_u32;
        let mut clear_iterations = 1_u32;
        let mut clear_residual_threshold = 1.1_f32;
        let mut clear_region_radius = 0_u32;
        let mut clear_pixel_moa_recovery = false;
        let mut emit_region_masks = false;
        let mut emit_text_cutouts = false;
        let mut emit_depth_probes = false;
        let mut emit_pixel_moa_probes = false;
        let mut emit_surface_probes = false;
        let mut monocular_cue_blend = 0.6_f32;

        let mut i = 0;
        while i < argv.len() {
            let token = &argv[i];
            let next = argv.get(i + 1);
            match token.as_str() {
                "--input" => {
                    input = Some(PathBuf::from(required(next, token)?));
                    i += 2;
                }
                "--out" => {
                    out_dir = PathBuf::from(required(next, token)?);
                    i += 2;
                }
                "--threshold" => {
                    threshold = required(next, token)?
                        .parse::<u8>()
                        .map_err(|_| "threshold must be 0..255".to_string())?;
                    i += 2;
                }
                "--limit" => {
                    limit = Some(
                        required(next, token)?
                            .parse::<usize>()
                            .map_err(|_| "limit must be a positive integer".to_string())?,
                    );
                    i += 2;
                }
                "--candidate-limit" => {
                    candidate_limit = required(next, token)?
                        .parse::<usize>()
                        .map_err(|_| "candidate-limit must be a positive integer".to_string())?
                        .max(1);
                    i += 2;
                }
                "--emit-cleared" => {
                    emit_cleared = true;
                    i += 1;
                }
                "--clear-threshold" => {
                    clear_threshold = required(next, token)?
                        .parse::<f32>()
                        .map_err(|_| "clear-threshold must be a finite number".to_string())?
                        .clamp(0.0, 1.0);
                    i += 2;
                }
                "--clear-radius" => {
                    clear_radius = required(next, token)?
                        .parse::<u32>()
                        .map_err(|_| "clear-radius must be a non-negative integer".to_string())?
                        .min(8);
                    i += 2;
                }
                "--clear-iterations" => {
                    clear_iterations = required(next, token)?
                        .parse::<u32>()
                        .map_err(|_| "clear-iterations must be a positive integer".to_string())?
                        .max(1)
                        .min(12);
                    i += 2;
                }
                "--clear-residual-threshold" => {
                    clear_residual_threshold = required(next, token)?
                        .parse::<f32>()
                        .map_err(|_| {
                            "clear-residual-threshold must be a finite number".to_string()
                        })?
                        .clamp(0.0, 1.1);
                    i += 2;
                }
                "--clear-region-radius" => {
                    clear_region_radius = required(next, token)?
                        .parse::<u32>()
                        .map_err(|_| {
                            "clear-region-radius must be a non-negative integer".to_string()
                        })?
                        .min(24);
                    i += 2;
                }
                "--clear-pixel-moa-recovery" => {
                    clear_pixel_moa_recovery = true;
                    i += 1;
                }
                "--emit-region-masks" => {
                    emit_region_masks = true;
                    i += 1;
                }
                "--emit-text-cutouts" => {
                    emit_text_cutouts = true;
                    i += 1;
                }
                "--emit-depth-probes" => {
                    emit_depth_probes = true;
                    i += 1;
                }
                "--emit-pixel-moa-probes" => {
                    emit_pixel_moa_probes = true;
                    i += 1;
                }
                "--emit-surface-probes" => {
                    emit_surface_probes = true;
                    i += 1;
                }
                "--monocular-cue-blend" => {
                    monocular_cue_blend = required(next, token)?
                        .parse::<f32>()
                        .map_err(|_| "monocular-cue-blend must be a finite number".to_string())?
                        .clamp(0.0, 1.0);
                    i += 2;
                }
                "--slug" => {
                    slug = required(next, token)?.to_string();
                    i += 2;
                }
                "--source-uri" => {
                    source_uri = required(next, token)?.to_string();
                    i += 2;
                }
                "--help" | "-h" => return Err(usage()),
                _ => return Err(format!("unknown argument: {}\n{}", token, usage())),
            }
        }

        Ok(Self {
            input: input.ok_or_else(usage)?,
            out_dir,
            threshold,
            limit,
            candidate_limit,
            slug,
            source_uri,
            emit_cleared,
            clear_threshold,
            clear_radius,
            clear_iterations,
            clear_residual_threshold,
            clear_region_radius,
            clear_pixel_moa_recovery,
            emit_region_masks,
            emit_text_cutouts,
            emit_depth_probes,
            emit_pixel_moa_probes,
            emit_surface_probes,
            monocular_cue_blend,
        })
    }
}

fn required<'a>(next: Option<&'a String>, flag: &str) -> Result<&'a str, String> {
    next.map(String::as_str)
        .filter(|v| !v.starts_with("--"))
        .ok_or_else(|| format!("missing value for {}", flag))
}

fn usage() -> String {
    "usage: why-text-topology --input DIR_OR_IMAGE --out DIR [--threshold 125] [--limit N] [--candidate-limit N] [--emit-cleared] [--emit-region-masks] [--emit-text-cutouts] [--emit-depth-probes] [--emit-pixel-moa-probes] [--emit-surface-probes] [--clear-threshold 0.75] [--clear-radius 1] [--clear-iterations 1] [--clear-residual-threshold 1.1] [--clear-region-radius 0] [--clear-pixel-moa-recovery] [--monocular-cue-blend 0.6]".to_string()
}

fn collect_images(input: &Path) -> Result<Vec<PathBuf>, String> {
    if input.is_file() {
        return Ok(vec![input.to_path_buf()]);
    }
    let mut out = Vec::new();
    for entry in fs::read_dir(input).map_err(|e| format!("read_dir {}: {}", input.display(), e))? {
        let path = entry.map_err(|e| e.to_string())?.path();
        if path.is_dir() {
            out.extend(collect_images(&path)?);
            continue;
        }
        if is_image_path(&path) {
            out.push(path);
        }
    }
    Ok(out)
}

fn is_image_path(path: &Path) -> bool {
    matches!(
        path.extension()
            .and_then(|s| s.to_str())
            .map(|s| s.to_ascii_lowercase())
            .as_deref(),
        Some("png" | "jpg" | "jpeg" | "gif" | "webp")
    )
}

fn write_examples_jsonl(path: &Path, examples: &[TextTopologyExample]) -> Result<(), String> {
    let file = File::create(path).map_err(|e| e.to_string())?;
    let mut writer = BufWriter::new(file);
    for example in examples {
        let line = serde_json::to_string(example).map_err(|e| e.to_string())?;
        writer
            .write_all(line.as_bytes())
            .map_err(|e| e.to_string())?;
        writer.write_all(b"\n").map_err(|e| e.to_string())?;
    }
    writer.flush().map_err(|e| e.to_string())
}

fn build_payload(
    args: &Args,
    examples: &[TextTopologyExample],
) -> Result<RosettaImportPayload, String> {
    let mut candidates = build_rosetta_candidates(examples);
    let total_candidates = candidates.len();
    candidates.truncate(args.candidate_limit);
    let high_text_like_candidates = candidates
        .iter()
        .filter(|c| c.consensus_target == "language_stroke_topology")
        .count();
    let top_candidates: Vec<ImportCandidate> = candidates
        .iter()
        .map(|candidate| ImportCandidate {
            symbol: candidate.symbol.clone(),
            consensus_target: candidate.consensus_target.clone(),
            consensus_confidence: candidate.consensus_confidence,
            utility_band: candidate.utility_band.clone(),
            best_candidate: ImportBestCandidate {
                predicted_meaning: candidate.predicted_meaning.clone(),
                score: candidate.score,
                support: candidate.support,
                support_count: candidate.support_count,
                avg_confidence: candidate.avg_confidence,
                matched_ratio: candidate.matched_ratio,
                collision_size: candidate.collision_size,
            },
            alternates: vec![ImportAlternate {
                predicted_meaning: "drawing_or_decoration".to_string(),
                score: 1.0 - candidate.score,
            }],
        })
        .collect();

    let candidate_symbols: HashSet<String> = candidates.iter().map(|c| c.symbol.clone()).collect();
    let bridge_entries: Vec<_> = examples
        .iter()
        .flat_map(build_bridge_entries)
        .filter(|entry| candidate_symbols.contains(&entry.symbol))
        .collect();
    let text_line_candidates: Vec<_> = examples
        .iter()
        .flat_map(|example| build_text_line_candidates(example, 0.55))
        .collect();
    let residual_text_artifacts: Vec<_> = examples
        .iter()
        .flat_map(|example| build_residual_text_artifacts(example, 0.55))
        .collect();
    let residual_review_queue = build_residual_review_queue(&residual_text_artifacts);
    let mesh_text_admission_ledger: Vec<_> = examples
        .iter()
        .flat_map(|example| build_mesh_text_admission_ledger(example, 0.55))
        .collect();
    let image_summary: Vec<_> = examples
        .iter()
        .map(|example| {
            let high = example
                .components
                .iter()
                .filter(|c| c.text_likeness >= 0.75)
                .count();
            serde_json::json!({
                "imageId": example.image_id,
                "path": example.path,
                "width": example.width,
                "height": example.height,
                "inkPixels": example.ink_pixels,
                "components": example.components.len(),
                "highTextLikeComponents": high,
            })
        })
        .collect();
    let collision_count = build_rosetta_candidates(examples)
        .into_iter()
        .filter(|c| c.collision_size > 0)
        .count() as u32;

    Ok(RosettaImportPayload {
        run: RosettaRun {
            slug: args.slug.clone(),
            label: "_why text topology corpus".to_string(),
            source_type: "image_stroke_topology".to_string(),
            source_uri: args.source_uri.clone(),
            input: serde_json::json!({
                "schema": "why_text_topology_input/v1",
                "imageCount": examples.len(),
                "candidateLimit": args.candidate_limit,
            }),
        },
        metrics: vec![RosettaMetric {
            iteration: 0,
            best_fitness: 0.0,
            anchor_recovery: 0.0,
            anchors_matched: 0,
            anchors_total: 0,
            collision_count,
            trend: "flat".to_string(),
            raw: serde_json::json!({
                "candidateCount": total_candidates,
                "textLineCandidateCount": text_line_candidates.len(),
                "residualTextArtifactCount": residual_text_artifacts.len(),
                "residualReviewQueueCount": residual_review_queue.len(),
                "meshTextAdmissionRecordCount": mesh_text_admission_ledger.len(),
                "domain": "handwritten_comic_text_topology",
            }),
        }],
        candidate_ranking: RosettaCandidateRanking {
            generated_at: "local".to_string(),
            iterations: 0,
            top_candidates,
            last_summary: serde_json::json!({
                "candidateCount": total_candidates,
                "imageCount": examples.len(),
                "highTextLikeCandidates": high_text_like_candidates,
                "textLineCandidateCount": text_line_candidates.len(),
                "residualTextArtifactCount": residual_text_artifacts.len(),
                "residualReviewQueueCount": residual_review_queue.len(),
                "meshTextAdmissionRecordCount": mesh_text_admission_ledger.len(),
            }),
        },
        artifacts: RosettaArtifacts {
            text_topology_corpus: serde_json::json!({
                "schema": "text_topology_corpus_reference/v1",
                "format": "jsonl",
                "path": "text-topology-corpus.jsonl",
                "examples": examples.len(),
                "note": "Full topology corpus is emitted beside this compact Rosetta import payload.",
            }),
            text_topology_bridge: serde_json::json!({
                "schema": "text_topology_bridge/v1",
                "scope": "ranked_candidates_only",
                "entries": bridge_entries,
            }),
            text_line_candidates: serde_json::json!({
                "schema": "text_line_candidates/v1",
                "admission": "language_shaped_topology_not_ocr",
                "entries": text_line_candidates,
            }),
            residual_text_artifacts: serde_json::json!({
                "schema": "residual_text_artifacts/v1",
                "scope": "primary_ink_near_admitted_language_bands",
                "entries": residual_text_artifacts,
            }),
            residual_review_queue: serde_json::json!({
                "schema": "residual_review_queue/v1",
                "ranking": "line_grouped_residual_priority",
                "entries": residual_review_queue,
            }),
            mesh_text_admission_ledger: serde_json::json!({
                "schema": "mesh_text_admission_ledger/v1",
                "grammar": "subject_object_verb_frfvi",
                "states": "positive_presence_positive_absence_negative_unknown_inactive_demotion",
                "entries": mesh_text_admission_ledger,
            }),
            image_summary: serde_json::json!({
                "schema": "why_image_summary/v1",
                "images": image_summary,
            }),
        },
    })
}
